import Foundation
import CoreBluetooth

extension BleDevice {

    func sendData(data: Data, writeType: BleDeviceWriteType, timeOut: TimeInterval, success: SuccessCallback?, failed: FailedCallback?) {

        let characteristic = writeType == .withResponse ? writeWithResChar : writeWithNoResChar
        let cbwriteType: CBCharacteristicWriteType = writeType == .withResponse ? .withResponse : .withoutResponse

        guard let peripheral = self.peripheral else {
            failed?(BleDeviceError.bleNotConnect)
            return
        }

        guard let characteristic = characteristic else {
            failed?(BleDeviceError.characteristicNotFound)
            return
        }

        Log.i("[蓝牙写数据]", "写数据开始", data.description)
        writeDataCancellables = peripheral.writeValue(data, for: characteristic, type: cbwriteType)
            .receive(on: DispatchQueue.main)
            .timeout(.seconds(timeOut), scheduler: DispatchQueue.main, customError: { BleDeviceError.writeTimeOut })
            .handleEvents(
                receiveCancel: {
                    Log.i("[蓝牙写数据]", "写数据开始 被取消", data.description)
                    failed?( BleDeviceError.unconnectable )
                }
            )
            .sink(receiveCompletion: {[weak self] completion in
                switch completion {
                case .failure(let errorInfo):
                    Log.i("[蓝牙写数据]", "写数据失败 error \(errorInfo)", data.description)
                    failed?( errorInfo as? BleDeviceError ?? .writeError )
                case .finished: break
                }

            }, receiveValue: {[weak self] in
                Log.i("[蓝牙写数据]", "写数据成功", data.description)
                success?()
            })
    }

}

