private func writeValueWithResponse(...) {
    return Deferred {
        let subject = PassthroughSubject<Void, Error>()
        var cancellable: AnyCancellable? = nil
        // 1. 先建立对 delegate 的订阅
        cancellable = self.didWriteValueForCharacteristic
            .filterFirstValueOrThrow(...)
            .sink { ... subject.send(...) }
        // 2. 再触发写入
        self._writeValueForCharacteristic(value, ...)
        return subject
    }.eraseToAnyPublisher()
}

