public lazy var bleSendFlow: BleSendDataFlow = {
    return BleSendDataFlow(dataSendImp: self)
}()

var peripheral: Peripheral? {
    didSet {
        monitorConnection()
    }
}

var writeWithResChar: CBCharacteristic?
var writeWithNoResChar: CBCharacteristic?
var notifyChar: CBCharacteristic?
var indicateChar: CBCharacteristic?

init(ssidPrefix: String, macAddress: String, useScanUUIDs: Bool, useRssiNotify: Bool) {
    self.macAddress = macAddress
    self.ssidPrefix = ssidPrefix
    self.name = BLEUtility.ssid(macAddress, ssidPrefix: ssidPrefix)
    self.cbuuids = useScanUUIDs ? [CBUUID(string: BLEUtility.uuid(self.name))] : nil
    self.useScanUUIDs = useScanUUIDs
    self.useRssiNotify = useRssiNotify
}

func disconnect() {
    if let peripheral = peripheral {
        centralManager.cancelPeripheralConnection(peripheral)
    }

    Log.i(tag:"\(position)蓝牙连接", "蓝牙连接 主动断开")
    cleanCache()
    state = .NotConnected

}

func connect() {
    guard state == .NotConnected else { return }

    guard centralManager.state == .poweredOn else {
        Log.i(tag:"\(position)蓝牙连接", "蓝牙连接 系统蓝牙开关未开启")
        return
    }

    cleanCache()
    state = .Scanning

    Log.i(tag:"\(position)蓝牙连接", "蓝牙连接 系统蓝牙开关 已开启，进入扫描/获取缓存流程")
    handleConnect()
}

func cleanCache() {
    self.peripheral = nil
    cancellables.removeAll()
    stateCancellable = nil
    bleStateCancellable = nil
    notifyCancellable = nil
    indicateCancellable = nil
    writeDataCancellables = nil

    characteristics = nil
}

func readRssi() {
    guard let peripheral = peripheral, peripheral.state == .connected else { return}
    peripheral._readRSSI()
}

func startDetect(_ count: Int = 5) -> AnyPublisher<DiscoveryPeripheral, Never>  {
    let scanOpt = CentralManager.ScanOptions.init(allowDuplicates: true)
    return self.centralManager.scanForPeripheralsV2(withServices: cbuuids, options: scanOpt)
}

func stopScan() {
    centralManager._stopScan()
    Log.i("蓝牙连接 停止扫描")
}


func fetchPeripheral() -> AnyPublisher<DiscoveryPeripheral, Never> {

    var peripheral: Peripheral?
    if let cache = fetchCachePeripheral() {
        peripheral = cache
        Log.i(tag:"\(position)蓝牙连接", "蓝牙连接 发现缓存 连接状态 \(cache.state.rawValue)")
    }
    if let peripheral {
        Log.i(tag:"\(position)蓝牙连接", "蓝牙连接 开始连接")
        return Just(DiscoveryPeripheral(peripheral: peripheral, advertisementData: nil)).eraseToAnyPublisher()
    }

    Log.i(tag:"\(position)蓝牙连接", "蓝牙连接 开始扫描 LocalName:\(self.name) UUIDs:\(String(describing: cbuuids))")
    return centralManager.scanForPeripherals(withServices: cbuuids)

