import Foundation

public class BleSendData: NSObject {

    let timeout: TimeInterval
    var delayTime: TimeInterval // 蓝牙包发送的间隔
    let controlId: UInt8?
    let sendData: [Data]
    let tBoxToken: String?      // 目前仅双发闭锁使用
    let tBoxCommand: BleBoxCommand?
    var parkingHeartCommand: BleParkingHeartCommand?

    init(timeout: TimeInterval = 5,
         delayTime: TimeInterval = 0.01,
         controlId: UInt8? = nil,
         sendData: [Data],
         tBoxCommand: BleBoxCommand? = nil,
         tBoxToken: String? = nil) {
        self.timeout = timeout
        self.delayTime = delayTime
        self.controlId = controlId
        self.sendData = sendData
        self.tBoxCommand = tBoxCommand
        self.tBoxToken = tBoxToken
    }

    public override var description: String {

        if let parkingHeartCommand = parkingHeartCommand {
            return "controlId: \(controlId ?? 0) parkingHeartCommand: \(parkingHeartCommand) sendData: \(sendData) "
        }

        return "controlId: \(controlId ?? 0) tBoxCommand: \(tBoxCommand) sendData: \(sendData)"
    }
}


class BleControlIdCreate {
    private static var sendId: UInt8 = 5
    static let semaphore = DispatchSemaphore(value: 1) // 信号量
    static func getControlId() -> UInt8 {
        semaphore.wait()
        if sendId >= 255 {
            sendId = 5
        } else {
            sendId += 1
        }
        semaphore.signal()
        return sendId
    }
}

