This is the most important class for understanding BLE lifecycle. It reactively computes two key booleans by subscribing to **all** `AppRunState` signals:

```swift
func calcSwitchState() {
    DispatchQueue.main.async() {
        var isNeedsConnect = true

        // Suspended if business logic says "wait"
        if self.isWaitingToConnect { isNeedsConnect = false }
        // Suspended during channel switch
        if self.isSwitchBleChannel { isNeedsConnect = false }
        // Suspended if BT radio is off
        if BleCentral.shared.start().state != .poweredOn { isNeedsConnect = false }
        // KEY: suspended in background UNLESS a condition permits background BLE
        if AppRunState.shared.isInBackground && !self.connectIfneedInBg && !self.isSendingBLECommand {
            isNeedsConnect = false
        }

        // Heartbeat: only on in background WITH polling active (or always for Polling 2.0)
        var turnOnCalc = false
        if !AppRunState.shared.isOnParking {
            if (AppRunState.shared.isInBackground && self.isPollingActive) || self.isPollingSecond {
                turnOnCalc = true
            }
        }
    }
}

// Background connect permission logic:
var connectIfneedInBg: Bool {
    if AppRunState.shared.isInBackground {
        if needDisconnectInBackground { return false }  // Passenger mode: disconnect in bg
        if isE28 { return false }                       // E28 model: disconnect in bg
        return true                                     // Default: stay connected in bg
    }
    return true
}
```

