        self?.checkIfNeedSendHeartbeat()
    }
    RunLoop.current.add(timer, forMode: .common)  // Added with .common to survive UI interaction
    self.heartBeatTimer = timer                   // Retained on the object
}

func stopHeartbeat() {
    self.heartBeatTimer?.invalidate()
    self.heartBeatTimer = nil
}
