## 2. Background State Tracking

The SDK has a **two-layer architecture** for background state: a raw `ApplicationState` layer and a business-logic `AppRunState` layer.

---

### Layer 1: `ApplicationState` — Raw UIKit Notifications

**File:** `XPVehicleSDK/VehicleControl/Utilities/Tools/ApplicationState.swift`

```swift
class ApplicationState {
    static let shared = ApplicationState()
    @Published var applicationState: UIApplication.State  // Combine @Published
    @Published var isWillTerminate: Bool

    var backGroundTask: UIBackgroundTaskIdentifier = .invalid
    var timer: Timer?  // 1-second countdown timer while in background

    init() {
        // Registers for all four system lifecycle notifications:
        NotificationCenter.default.addObserver(self, selector: #selector(didEnterBackgroundNotification),
            name: UIApplication.didEnterBackgroundNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(willEnterForegroundNotification),
            name: UIApplication.willEnterForegroundNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(didBecomeActiveNotification),
            name: UIApplication.didBecomeActiveNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(willTerminateNotification),
            name: UIApplication.willTerminateNotification, object: nil)
    }

    @objc func didEnterBackgroundNotification() {
        applicationState = .background
        _beginBackgroundTask()  // Requests background execution time
    }

    @objc func willEnterForegroundNotification() {
        applicationState = .active
        _endBackgroundTask()
        stopTimer()
    }

    // Background Task lifecycle
    func _beginBackgroundTask() {
        backGroundTask = UIApplication.shared.beginBackgroundTask(expirationHandler: {
            self._endBackgroundTask()
        })
        startTimer()  // Starts 1s countdown polling
    }

    // Monitors remaining background time every 1 second
    @objc func readActiveTime() {
        let time = UIApplication.shared.backgroundTimeRemaining
        if time < 5, !isSendSubsent {
            isSendSubsent = true
            // Fires .ApplicationWillSuspended notification — MQTT uses this to pre-disconnect
            NotificationCenter.default.post(name: .ApplicationWillSuspended, object: nil)
            stopTimer()
        }
    }
}
```

**Key behaviors:**
- Actively requests `beginBackgroundTask` on every background entry
- Polls `backgroundTimeRemaining` every 1 second
- At `< 5 seconds` remaining, fires custom `.ApplicationWillSuspended` notification
- Also has a custom `.ApplicationDidUnsuspend` notification (defined but not shown fired in this file)

